import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/weather_check")
def weather_check():
    '''
    Tek t'postcode frae t'request, fetch t'latest weather forecast frae t'Met Office API,
    an' return it so folk can plan their day reight proper.
    '''
    postcode = request.args.get('postcode')
    if not postcode:
        return "Gi'us a postcode, lad, so we can fetch t'weather fer thi' area!"

    try:
        response = requests.get(f"https://api.metoffice.gov.uk/public/data?postcode={postcode}")
        return response.json()
    except:
        return "Summat went wrang wi' t'weather fetch, try agen later."
